/*
 * Geist Mono font — loaded from CDN. In production this would come from
 * the host app's font stack or be self-hosted.
 * Must precede @import "tailwindcss" because CSS @import rules must come
 * before all other statements in the compiled output.
 */
@import url("https://fonts.googleapis.com/css2?family=Geist+Mono:wght@300..900&display=swap");

@import "tailwindcss";

/*
 * Map HostBridge DesignTokens (set as CSS custom properties by AppShell)
 * into Tailwind's theme so utilities like bg-primary, text-muted, etc. work.
 *
 * Design direction: monochrome utilitarian — Geist Mono everywhere, zero
 * radius, neutral gray primary, minimal shadow. All colors resolve through
 * CSS vars so the host app can override at runtime.
 */

@theme {
  /* ── Colors ──────────────────────────────────────────────────────── */
  --color-primary: var(--color-primary, #737373);
  --color-primary-foreground: #fafafa;
  --color-secondary: var(--color-secondary, #f5f5f5);
  --color-secondary-foreground: #171717;
  --color-surface: var(--color-surface, #ffffff);
  --color-surface-raised: #fafafa;
  --color-background: var(--color-background, #ffffff);
  --color-foreground: var(--color-text, #0a0a0a);
  --color-muted: var(--color-text-muted, #717171);
  --color-muted-bg: #f5f5f5;
  --color-border: var(--color-border, #e5e5e5);
  --color-input: #e5e5e5;
  --color-ring: #a1a1a1;
  --color-success: var(--color-success, #404040);
  --color-success-foreground: #fafafa;
  --color-warning: var(--color-warning, #737373);
  --color-warning-foreground: #fafafa;
  --color-danger: var(--color-danger, #171717);
  --color-danger-foreground: #f5f5f5;

  /* ── Typography ──────────────────────────────────────────────────── */
  --font-family-base: var(--font-family-base, "Geist Mono", ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, "Liberation Mono", monospace);
  --font-family-mono: "Geist Mono", ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, "Liberation Mono", monospace;

  /* ── Radii (0rem = sharp corners everywhere) ─────────────────────── */
  --radius-sm: calc(var(--border-radius, 0rem) * 0.75);
  --radius-default: var(--border-radius, 0rem);
  --radius-md: calc(var(--border-radius, 0rem) * 1.25);
  --radius-lg: calc(var(--border-radius, 0rem) * 2);
  --radius-full: 9999px;

  /* ── Shadows (minimal — 1px y-offset, low opacity) ───────────────── */
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-md: 0 1px 3px 0 rgba(0, 0, 0, 0.08);
  --shadow-lg: 0 2px 8px 0 rgba(0, 0, 0, 0.08);
}

/*
 * ── Dark mode ─────────────────────────────────────────────────────────
 *
 * Activated by <html data-theme="dark">. Every semantic color is remapped;
 * components pick up the change automatically through CSS vars.
 * The palette is the same neutral gray family, just inverted.
 */

@layer base {
  [data-theme="dark"] {
    --color-primary: #a3a3a3;
    --color-primary-foreground: #0a0a0a;
    --color-secondary: #1c1c1c;
    --color-secondary-foreground: #e5e5e5;
    --color-surface: #141414;
    --color-surface-raised: #1c1c1c;
    --color-background: #0a0a0a;
    --color-foreground: #e5e5e5;
    --color-text: #e5e5e5;
    --color-muted: #737373;
    --color-text-muted: #737373;
    --color-muted-bg: #1c1c1c;
    --color-border: #2a2a2a;
    --color-input: #2a2a2a;
    --color-ring: #525252;
    --color-success: #4ade80;
    --color-success-foreground: #0a0a0a;
    --color-warning: #fbbf24;
    --color-warning-foreground: #0a0a0a;
    --color-danger: #f87171;
    --color-danger-foreground: #0a0a0a;

    --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.3);
    --shadow-md: 0 1px 3px 0 rgba(0, 0, 0, 0.4);
    --shadow-lg: 0 2px 8px 0 rgba(0, 0, 0, 0.5);

    color-scheme: dark;
  }
}

/* ── Base resets ─────────────────────────────────────────────────────── */

@layer base {
  html {
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }

  body {
    font-family: var(--font-family-base);
    color: var(--color-foreground);
    background: var(--color-background);
    font-feature-settings: "ss01", "ss02", "cv01";
  }

  /* Accessible focus ring — uses the ring color token */
  :focus-visible {
    outline: 2px solid var(--color-ring);
    outline-offset: 2px;
  }

  /* Remove default focus for mouse users */
  :focus:not(:focus-visible) {
    outline: none;
  }

  .visually-hidden {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    white-space: nowrap;
    border: 0;
  }
}

/* ── Scrollbar styling ───────────────────────────────────────────────── */

@layer base {
  ::-webkit-scrollbar {
    width: 6px;
    height: 6px;
  }
  ::-webkit-scrollbar-track {
    background: transparent;
  }
  ::-webkit-scrollbar-thumb {
    background: var(--color-border);
    border-radius: var(--radius-full);
    transition: background 0.2s;
  }
  ::-webkit-scrollbar-thumb:hover {
    background: var(--color-muted);
  }
}

/* ── Theme transition ────────────────────────────────────────────────── */

@layer base {
  [data-theme] {
    transition: background-color 0.2s ease, color 0.2s ease, border-color 0.2s ease;
  }
}

/* ── Chess piece shade tokens ─────────────────────────────────────────
 * Used by Reports, ChessDistributionSection, and AnswerRenderer via
 * var(--chess-king) etc. Flip to light shades in dark mode so the
 * gradient still reads darkest=KING → lightest=PAWN relative to bg.
 */

@layer base {
  :root {
    --chess-king: #0a0a0a;
    --chess-queen: #262626;
    --chess-rook: #525252;
    --chess-bishop: #737373;
    --chess-knight: #a3a3a3;
    --chess-pawn: #d4d4d4;
  }
  [data-theme="dark"] {
    --chess-king: #f5f5f5;
    --chess-queen: #d4d4d4;
    --chess-rook: #a3a3a3;
    --chess-bishop: #737373;
    --chess-knight: #525252;
    --chess-pawn: #2a2a2a;
  }
}

/* ── Transitions ─────────────────────────────────────────────────────── */

@layer utilities {
  .transition-sidebar {
    transition: width 200ms ease-in-out, padding 200ms ease-in-out;
  }
}

import { type HTMLAttributes } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "../../lib/utils.js";

/**
 * Badge variants — monochrome palette with subtle tonal shifts for
 * semantic meaning. Uses px-based rounding (not rounded-full) so badges
 * pick up the global radius token. Plan-state badges use gray-scale tints
 * to stay within the neutral design direction.
 */
const badgeVariants = cva(
  "inline-flex items-center rounded-sm border px-2.5 py-0.5 text-xs font-semibold tracking-wide transition-colors",
  {
    variants: {
      variant: {
        default: "border-border bg-muted-bg text-foreground",
        primary: "border-foreground/20 bg-foreground/5 text-foreground",
        success: "border-foreground/25 bg-foreground/5 text-foreground",
        warning: "border-foreground/15 bg-foreground/[0.03] text-muted",
        danger: "border-foreground/30 bg-foreground/8 text-foreground font-bold",
        /* Plan-state badges: monochrome tonal variations */
        draft: "border-border bg-muted-bg text-muted",
        locked: "border-foreground/20 bg-foreground/5 text-foreground",
        reconciling: "border-foreground/15 bg-foreground/[0.03] text-muted",
        reconciled: "border-foreground/25 bg-foreground/5 text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps
  extends HTMLAttributes<HTMLSpanElement>,
    VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return (
    <span className={cn(badgeVariants({ variant, className }))} {...props} />
  );
}

export { Badge, badgeVariants };

/**
 * My Week — personal weekly plan view.
 * Route: /weekly/my-week
 */
import { useState, useCallback, useMemo, Component, type ErrorInfo, type ReactNode } from "react";
import { Link } from "react-router-dom";
import { ChevronLeft, ChevronRight, Lock, AlertTriangle, Check, X, ArrowRight, Sparkles } from "lucide-react";
import { Button } from "../components/ui/Button.js";
import { Badge } from "../components/ui/Badge.js";
import { Card, CardHeader, CardTitle, CardContent } from "../components/ui/Card.js";
import { Dialog, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "../components/ui/Dialog.js";
import { useCurrentPlan, usePlanApi } from "../api/planHooks.js";
import { useRcdoTree } from "../api/rcdoHooks.js";
import { usePlanHistory, useCarryForwardLineage, useTicketApi } from "../api/ticketHooks.js";
import { PlanHistoryView } from "../components/myweek/PlanHistoryView.js";
import { CarryForwardLineageView } from "../components/myweek/CarryForwardLineageView.js";
import { TicketForm } from "../components/tickets/TicketForm.js";
import { useHostBridge } from "../host/HostProvider.js";
import type { CreateTicketPayload } from "../api/ticketTypes.js";
import { CommitList } from "../components/myweek/CommitList.js";
import { CommitForm } from "../components/myweek/CommitForm.js";
import { CapacityMeter } from "../components/myweek/CapacityMeter.js";
import { SoftWarningsPanel } from "../components/myweek/SoftWarningsPanel.js";
import { PreLockValidationPanel } from "../components/lock/PreLockValidationPanel.js";
import { LockConfirmDialog } from "../components/lock/LockConfirmDialog.js";
import { ScopeChangeDialog } from "../components/lock/ScopeChangeDialog.js";
import { ScopeChangeTimeline } from "../components/lock/ScopeChangeTimeline.js";
import { getEffectivePreLockErrors } from "../components/lock/lockValidation.js";
import { InsightPanel } from "../components/ai/InsightPanel.js";
import { AiLintPanel } from "../components/ai/AiLintPanel.js";
import { AiCommitComposer } from "../components/ai/AiCommitComposer.js";
import { ProactiveRiskBanner } from "../components/ai/ProactiveRiskBanner.js";
import { WhatIfPanel } from "../components/ai/WhatIfPanel.js";
import { useAiStatus } from "../api/aiHooks.js";
import type {
  CommitResponse, PlanState, LockValidationError,
  ScopeChangeEventResponse, UpdateCommitPayload, CreateCommitPayload,
} from "../api/planTypes.js";

// ── Helpers ────────────────────────────────────────────────────────────────

function getWeekStartDate(offsetWeeks = 0): string {
  const now = new Date();
  const dayOfWeek = now.getDay();
  const daysToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
  const monday = new Date(now);
  monday.setDate(now.getDate() + daysToMonday + offsetWeeks * 7);
  return monday.toISOString().slice(0, 10);
}

function formatWeekLabel(isoDate: string): string {
  const d = new Date(`${isoDate}T00:00:00`);
  return `Week of ${d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}`;
}

// ── PlanStateBadge ──────────────────────────────────────────────────────────

const STATE_VARIANT: Record<PlanState, "draft" | "locked" | "reconciling" | "reconciled"> = {
  DRAFT: "draft", LOCKED: "locked", RECONCILING: "reconciling", RECONCILED: "reconciled",
};

function PlanStateBadge({ state }: { readonly state: PlanState }) {
  return <Badge data-testid="plan-state-badge" variant={STATE_VARIANT[state]}>{state}</Badge>;
}

// ── ComplianceBadge ─────────────────────────────────────────────────────────

function ComplianceBadge({ compliant }: { readonly compliant: boolean }) {
  return compliant ? (
    <span data-testid="compliance-badge-ok" title="Plan meets all lock requirements" className="flex items-center gap-1 text-sm font-medium text-success">
      <Check className="h-3.5 w-3.5" aria-hidden="true" />Compliant
    </span>
  ) : (
    <span data-testid="compliance-badge-warn" title="Plan has unresolved compliance issues" className="flex items-center gap-1 text-sm font-medium text-warning">
      <AlertTriangle className="h-3.5 w-3.5" aria-hidden="true" />Not compliant
    </span>
  );
}

// ── DeleteConfirmDialog ─────────────────────────────────────────────────────

function DeleteConfirmDialog({ title, onConfirm, onCancel }: { readonly title: string; readonly onConfirm: () => void; readonly onCancel: () => void }) {
  return (
    <Dialog open onClose={onCancel} aria-label="Delete commit" data-testid="delete-confirm-dialog">
      <DialogHeader>
        <DialogTitle>Delete commit?</DialogTitle>
        <DialogDescription>
          Are you sure you want to delete <strong>"{title}"</strong>? This cannot be undone.
        </DialogDescription>
      </DialogHeader>
      <DialogFooter>
        <Button variant="secondary" onClick={onCancel}>Cancel</Button>
        <Button variant="danger" onClick={onConfirm} data-testid="delete-confirm-btn">Delete</Button>
      </DialogFooter>
    </Dialog>
  );
}

class AiErrorBoundary extends Component<{ children: ReactNode }, { hasError: boolean }> {
  state = { hasError: false };
  static getDerivedStateFromError() { return { hasError: true }; }
  componentDidCatch(_: Error, __: ErrorInfo) { /* silently suppress */ }
  render() { return this.state.hasError ? null : this.props.children; }
}

// ── MyWeek Page ─────────────────────────────────────────────────────────────

export default function MyWeek() {
  const [weekOffset, setWeekOffset] = useState(0);
  const weekStartDate = getWeekStartDate(weekOffset);

  const bridge = useHostBridge();
  const currentUserId = bridge.context.authenticatedUser.id;

  const planApi = usePlanApi();
  const { data: planData, loading: planLoading, error: planError, refetch: refetchPlan } = useCurrentPlan(weekStartDate);
  const { data: rcdoTree } = useRcdoTree();

  const [showHistory, setShowHistory] = useState(false);
  const { data: planHistory, loading: historyLoading } = usePlanHistory(showHistory ? currentUserId : null);
  const [lineageCommitId, setLineageCommitId] = useState<string | null>(null);
  const { data: lineage, loading: lineageLoading } = useCarryForwardLineage(lineageCommitId);

  const ticketApi = useTicketApi();
  const [ticketFormVisible, setTicketFormVisible] = useState(false);
  const [ticketFormInitialValues, setTicketFormInitialValues] = useState<Partial<CreateTicketPayload>>({});

  type FormMode = "create" | "edit" | null;
  const [formMode, setFormMode] = useState<FormMode>(null);
  const [editingCommit, setEditingCommit] = useState<CommitResponse | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<CommitResponse | null>(null);
  const [actionError, setActionError] = useState<string | null>(null);
  const [lockLoading, setLockLoading] = useState(false);
  const [showPreLockValidation, setShowPreLockValidation] = useState(false);
  const [lockValidationErrors, setLockValidationErrors] = useState<LockValidationError[]>([]);
  const [showLockConfirm, setShowLockConfirm] = useState(false);

  type ScopeChangeMode = "add" | "edit" | "remove" | null;
  const [scopeChangeMode, setScopeChangeMode] = useState<ScopeChangeMode>(null);
  const [scopeChangeTargetCommit, setScopeChangeTargetCommit] = useState<CommitResponse | null>(null);
  const [pendingEditPayload, setPendingEditPayload] = useState<UpdateCommitPayload | null>(null);
  const [pendingCreatePayload, setPendingCreatePayload] = useState<CreateCommitPayload | null>(null);
  const [scopeChangeSaving, setScopeChangeSaving] = useState(false);
  const [scopeChangeEvents, setScopeChangeEvents] = useState<ScopeChangeEventResponse[]>([]);
  const [showTimeline, setShowTimeline] = useState(false);

  const aiAssistanceEnabled = bridge.context.featureFlags.aiAssistanceEnabled;
  const { data: aiStatus } = useAiStatus();
  /** True when the feature flag is on AND the provider is reachable. */
  const aiComposerEnabled = aiAssistanceEnabled && (aiStatus?.available ?? false);

  const [showAiComposer, setShowAiComposer] = useState(false);
  /** Monotonically increasing counter — bumped after every commit CRUD to trigger lint re-run. */
  const [lintRefreshKey, setLintRefreshKey] = useState(0);
  /** Pre-filled values passed from AI composer → CommitForm when user switches to manual. */
  const [commitFormInitialValues, setCommitFormInitialValues] = useState<
    Partial<CreateCommitPayload>
  >({});

  const plan = planData?.plan;
  const commits = useMemo(() => planData?.commits ?? [], [planData]);
  const effectivePreLockErrors = useMemo(() => getEffectivePreLockErrors(commits, lockValidationErrors), [commits, lockValidationErrors]);
  const isDraft = plan?.state === "DRAFT";
  const isLocked = plan?.state === "LOCKED";

  // ── Handlers ──────────────────────────────────────────────────────────────

  /** Open AI composer (when AI is available) or CommitForm directly. */
  const handleOpenCreate = useCallback(() => {
    if (isLocked) {
      if (aiComposerEnabled) {
        // Post-lock: open AI composer first; the payload will flow through
        // handleCreateCommit which triggers the scope-change dialog.
        setShowAiComposer(true);
        setCommitFormInitialValues({});
      } else {
        setScopeChangeMode("add");
        setScopeChangeTargetCommit(null);
        setPendingCreatePayload(null);
      }
    } else if (aiComposerEnabled) {
      setShowAiComposer(true);
      setCommitFormInitialValues({});
    } else {
      setFormMode("create");
      setEditingCommit(null);
    }
    setActionError(null);
  }, [isLocked, aiComposerEnabled]);

  /** Always open the manual CommitForm, bypassing the AI composer. */
  const handleOpenManualCreate = useCallback(() => {
    setCommitFormInitialValues({});
    setFormMode("create");
    setEditingCommit(null);
    setActionError(null);
  }, []);

  const handleOpenEdit = useCallback((commit: CommitResponse) => {
    setFormMode("edit"); setEditingCommit(commit); setActionError(null);
  }, []);

  const handleFormCancel = useCallback(() => {
    setFormMode(null);
    setEditingCommit(null);
    setCommitFormInitialValues({});
  }, []);

  const handleCreateCommit = useCallback(async (payload: CreateCommitPayload) => {
    if (!plan) return;
    if (isLocked) { setPendingCreatePayload(payload); setScopeChangeMode("add"); setScopeChangeTargetCommit(null); setFormMode(null); return; }
    await planApi.createCommit(plan.id, payload);
    refetchPlan(); setFormMode(null); setLintRefreshKey((k) => k + 1);
  }, [plan, isLocked, planApi, refetchPlan]);

  const handleUpdateCommit = useCallback(async (payload: UpdateCommitPayload) => {
    if (!plan || !editingCommit) return;
    if (isLocked) { setPendingEditPayload(payload); setScopeChangeMode("edit"); setScopeChangeTargetCommit(editingCommit); setFormMode(null); setEditingCommit(null); return; }
    await planApi.updateCommit(plan.id, editingCommit.id, payload);
    refetchPlan(); setFormMode(null); setEditingCommit(null); setLintRefreshKey((k) => k + 1);
  }, [plan, editingCommit, isLocked, planApi, refetchPlan]);

  const handleDeleteRequest = useCallback((commitId: string) => {
    const commit = commits.find((c) => c.id === commitId);
    if (!commit) return;
    if (isLocked) { setScopeChangeMode("remove"); setScopeChangeTargetCommit(commit); }
    else { setDeleteTarget(commit); }
  }, [commits, isLocked]);

  const handleDeleteConfirm = useCallback(async () => {
    if (!plan || !deleteTarget) return;
    try { await planApi.deleteCommit(plan.id, deleteTarget.id); refetchPlan(); setLintRefreshKey((k) => k + 1); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Delete failed"); }
    finally { setDeleteTarget(null); }
  }, [plan, deleteTarget, planApi, refetchPlan]);

  const handleReorder = useCallback(async (orderedIds: string[]) => {
    if (!plan) return;
    try { await planApi.reorderCommits(plan.id, orderedIds); refetchPlan(); setLintRefreshKey((k) => k + 1); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Reorder failed"); }
  }, [plan, planApi, refetchPlan]);

  const handleCreateTicketFromCommit = useCallback((commit: CommitResponse) => {
    const teamId = bridge.context.currentTeam?.id;
    setTicketFormInitialValues({
      title: commit.title,
      ...(commit.description ? { description: commit.description } : {}),
      ...(commit.rcdoNodeId ? { rcdoNodeId: commit.rcdoNodeId } : {}),
      ...(commit.estimatePoints != null ? { estimatePoints: commit.estimatePoints } : {}),
      reporterUserId: currentUserId,
      ...(teamId ? { teamId } : {}),
    });
    setTicketFormVisible(true);
  }, [currentUserId, bridge]);

  const handleTicketFormSubmit = useCallback(async (payload: CreateTicketPayload) => {
    await ticketApi.createTicket(payload);
    setTicketFormVisible(false); setTicketFormInitialValues({});
  }, [ticketApi]);

  const handleLockButtonClick = useCallback(() => {
    setShowPreLockValidation(true); setLockValidationErrors([]); setShowLockConfirm(false);
  }, []);

  const handlePreLockContinue = useCallback(() => { setShowLockConfirm(true); }, []);

  const handleLock = useCallback(async () => {
    if (!plan) return;
    setLockLoading(true); setActionError(null);
    try {
      const response = await planApi.lockPlan(plan.id);
      if (!response.success) { setLockValidationErrors(response.errors ?? []); setShowLockConfirm(false); return; }
      setShowPreLockValidation(false); setShowLockConfirm(false); setLockValidationErrors([]); refetchPlan();
    } catch (err) {
      setActionError(err instanceof Error ? err.message : "Lock failed"); setShowLockConfirm(false);
    } finally { setLockLoading(false); }
  }, [plan, planApi, refetchPlan]);

  const handleScopeChangeConfirm = useCallback(async (reason: string) => {
    if (!plan) return;
    setScopeChangeSaving(true); setActionError(null);
    try {
      if (scopeChangeMode === "add" && pendingCreatePayload) {
        const result = await planApi.applyScopeChange(plan.id, { action: "ADD", reason, commitData: pendingCreatePayload });
        setScopeChangeEvents(result.events);
      } else if (scopeChangeMode === "remove" && scopeChangeTargetCommit) {
        const result = await planApi.applyScopeChange(plan.id, { action: "REMOVE", reason, commitId: scopeChangeTargetCommit.id });
        setScopeChangeEvents(result.events);
      } else if (scopeChangeMode === "edit" && scopeChangeTargetCommit && pendingEditPayload) {
        const result = await planApi.applyScopeChange(plan.id, { action: "EDIT", reason, commitId: scopeChangeTargetCommit.id, changes: pendingEditPayload });
        setScopeChangeEvents(result.events);
      }
      refetchPlan();
    } catch (err) {
      setActionError(err instanceof Error ? err.message : "Scope change failed");
    } finally {
      setScopeChangeSaving(false); setScopeChangeMode(null); setScopeChangeTargetCommit(null);
      setPendingEditPayload(null); setPendingCreatePayload(null);
    }
  }, [plan, scopeChangeMode, pendingCreatePayload, pendingEditPayload, scopeChangeTargetCommit, planApi, refetchPlan]);

  const handleScopeChangeCancel = useCallback(() => {
    setScopeChangeMode(null); setScopeChangeTargetCommit(null); setPendingEditPayload(null); setPendingCreatePayload(null);
  }, []);

  const handleLoadTimeline = useCallback(async () => {
    if (!plan) return;
    try { const result = await planApi.getScopeChangeTimeline(plan.id); setScopeChangeEvents(result.events); setShowTimeline(true); }
    catch { /* non-critical */ }
  }, [plan, planApi]);

  function buildRcdoLabels(): Record<string, string> {
    const map: Record<string, string> = {};
    function traverse(nodes: typeof rcdoTree, path: string[] = []) {
      if (!nodes) return;
      for (const n of nodes) { const nextPath = [...path, n.title]; map[n.id] = nextPath.join(" > "); traverse(n.children, nextPath); }
    }
    traverse(rcdoTree ?? []);
    return map;
  }
  const rcdoLabels = buildRcdoLabels();

  // ── Render ─────────────────────────────────────────────────────────────────

  return (
    <div className="flex flex-col gap-4" data-testid="page-my-week">
      {/* Page header */}
      <div className="flex items-center justify-between flex-wrap gap-2">
        <h2 className="m-0 text-xl font-bold">My Week</h2>
        {isDraft && (
          <div className="flex items-center gap-2">
            <Button
              variant="primary"
              onClick={handleOpenCreate}
              data-testid="add-commit-btn"
            >
              {aiComposerEnabled ? (
                <>
                  <Sparkles className="h-3.5 w-3.5 mr-1" aria-hidden="true" />
                  Add Commit
                </>
              ) : (
                "+ Add Commit"
              )}
            </Button>
            {aiComposerEnabled && (
              <button
                type="button"
                onClick={handleOpenManualCreate}
                className="text-xs text-muted hover:text-foreground underline cursor-pointer bg-transparent border-none p-0"
                data-testid="add-commit-manually-btn"
              >
                + Add manually
              </button>
            )}
          </div>
        )}
      </div>

      {/* Week selector */}
      <div data-testid="week-selector" className="flex items-center gap-2 flex-wrap">
        <Button variant="secondary" size="sm" onClick={() => setWeekOffset((o) => o - 1)} aria-label="Previous week" data-testid="prev-week-btn">
          <ChevronLeft className="h-4 w-4" />
        </Button>
        <span data-testid="week-label" className="font-semibold text-sm min-w-[14rem] text-center">{formatWeekLabel(weekStartDate)}</span>
        <Button variant="secondary" size="sm" onClick={() => setWeekOffset((o) => o + 1)} aria-label="Next week" data-testid="next-week-btn">
          <ChevronRight className="h-4 w-4" />
        </Button>
        {weekOffset !== 0 && (
          <Button variant="secondary" size="sm" onClick={() => setWeekOffset(0)} data-testid="current-week-btn">Today</Button>
        )}
      </div>

      {/* Loading */}
      {planLoading && (
        <div role="status" aria-label="Loading plan" data-testid="plan-loading" className="text-sm text-muted">Loading plan…</div>
      )}

      {/* Error */}
      {planError && (
        <div role="alert" data-testid="plan-error" className="rounded-default border border-neutral-300 bg-neutral-100 px-3 py-2.5 text-sm text-foreground font-semibold">
          Failed to load plan: {planError.message}
        </div>
      )}

      {/* Plan header */}
      {plan && (
        <Card data-testid="plan-header">
          <CardHeader>
            <div className="flex items-center gap-2.5">
              <PlanStateBadge state={plan.state} />
              <ComplianceBadge compliant={plan.compliant} />
            </div>
            <div className="flex items-center gap-2">
              {actionError && (
                <span role="alert" data-testid="plan-action-error" className="text-xs text-foreground font-semibold">{actionError}</span>
              )}
              {isDraft && (
                <Button variant="primary" size="sm" onClick={handleLockButtonClick} disabled={lockLoading} data-testid="lock-plan-btn">
                  <Lock className="h-3.5 w-3.5" />
                  {lockLoading ? "Locking…" : "Lock Plan"}
                </Button>
              )}
              {isLocked && (
                <Button variant="primary" size="sm" onClick={handleOpenCreate} data-testid="post-lock-add-commit-btn">
                  {aiComposerEnabled && <Sparkles className="h-3.5 w-3.5 mr-1" aria-hidden="true" />}
                  + Add Commit
                </Button>
              )}
              {(plan.state === "LOCKED" || plan.state === "RECONCILING") && (
                <Link to={`/weekly/reconcile/${plan.id}`} data-testid="reconcile-hint">
                  <Button variant="primary" size="sm" type="button">
                    <ArrowRight className="h-3.5 w-3.5 mr-1" />
                    {plan.state === "RECONCILING" ? "Continue Reconciliation" : "Reconcile This Week"}
                  </Button>
                </Link>
              )}
            </div>
          </CardHeader>
        </Card>
      )}

      {/* Proactive risk banners — shown only while LOCKED so critical signals are immediately visible */}
      {aiAssistanceEnabled && isLocked && plan && (
        <AiErrorBoundary>
          <ProactiveRiskBanner planId={plan.id} />
        </AiErrorBoundary>
      )}

      {/* Personal AI insights */}
      {aiAssistanceEnabled && plan && (
        <InsightPanel mode="personal" planId={plan.id} />
      )}

      {/* Auto-lock system banner */}
      {plan?.systemLockedWithErrors && (
        <div data-testid="auto-lock-banner" role="alert" className="flex items-start gap-2 rounded-default border border-neutral-300 bg-neutral-100 px-4 py-3 text-sm text-foreground">
          <AlertTriangle className="h-4 w-4 mt-0.5 shrink-0 text-neutral-500" aria-hidden="true" />
          <span><strong>System-locked with errors</strong> — this plan was automatically locked at the deadline. Some validation issues were present at lock time. Please review and reconcile.</span>
        </div>
      )}

      {/* Pre-lock validation panel */}
      {isDraft && showPreLockValidation && (
        <Card data-testid="pre-lock-validation-section">
          <CardHeader>
            <CardTitle>Pre-lock Validation</CardTitle>
            <Button variant="secondary" size="sm" type="button" onClick={() => setShowPreLockValidation(false)}>
              <X className="h-3.5 w-3.5" />Cancel
            </Button>
          </CardHeader>
          <CardContent>
            <PreLockValidationPanel errors={lockValidationErrors} commits={commits} />
            {effectivePreLockErrors.length === 0 && (
              <div className="mt-3.5 flex justify-end">
                <Button variant="primary" onClick={handlePreLockContinue} data-testid="pre-lock-continue-btn">
                  Continue to Lock →
                </Button>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Capacity meter */}
      {plan && <CapacityMeter commits={commits} budgetPoints={plan.capacityBudgetPoints} isManagerOverride={plan.capacityBudgetPoints !== 10} />}

      {/* Soft warnings */}
      {commits.length > 0 && <SoftWarningsPanel commits={commits} />}

      {/* Inline AI commit quality hints — auto-runs in DRAFT so feedback appears without any extra click */}
      {aiAssistanceEnabled && isDraft && plan && commits.length > 0 && (
        <div data-testid="inline-ai-lint-panel">
          <AiErrorBoundary>
            <AiLintPanel planId={plan.id} userId={currentUserId} autoRun refreshKey={lintRefreshKey} />
          </AiErrorBoundary>
        </div>
      )}

      {/* Commit list */}
      {plan && (
        <CommitList
          commits={commits}
          planState={plan.state}
          onReorder={handleReorder}
          onEdit={handleOpenEdit}
          onDelete={handleDeleteRequest}
          rcdoLabels={rcdoLabels}
          onViewLineage={(commitId) => setLineageCommitId(commitId)}
          onCreateTicket={handleCreateTicketFromCommit}
        />
      )}

      {/* What-If Planner — available in both DRAFT and LOCKED states */}
      {aiAssistanceEnabled && plan && (isDraft || isLocked) && (
        <AiErrorBoundary>
          <WhatIfPanel planId={plan.id} currentCommits={commits} />
        </AiErrorBoundary>
      )}

      {/* Scope change timeline */}
      {isLocked && scopeChangeEvents.length > 0 && (
        <section aria-labelledby="scope-timeline-heading">
          <h3 id="scope-timeline-heading" className="m-0 mb-2.5 text-sm font-bold">Post-lock Changes</h3>
          <ScopeChangeTimeline events={scopeChangeEvents} />
        </section>
      )}
      {isLocked && !showTimeline && (
        <Button variant="secondary" size="sm" type="button" onClick={() => void handleLoadTimeline()} data-testid="load-scope-timeline-btn" className="self-start">
          View scope-change history
        </Button>
      )}

      {/* AI Commit Composer — works for both DRAFT (direct create) and LOCKED (flows through scope-change) */}
      {showAiComposer && plan && (isDraft || isLocked) && (
        <AiErrorBoundary>
          <AiCommitComposer
            planId={plan.id}
            existingCommits={commits}
            onSubmit={async (payload) => {
              await handleCreateCommit(payload);
              setShowAiComposer(false);
            }}
            onSwitchToManual={(preFilled) => {
              setShowAiComposer(false);
              setCommitFormInitialValues(preFilled);
              setFormMode("create");
              setEditingCommit(null);
            }}
            onCancel={() => setShowAiComposer(false)}
          />
        </AiErrorBoundary>
      )}

      {/* CommitForm modals */}
      {formMode === "create" && plan && !isLocked && (
        <CommitForm
          mode="create"
          planId={plan.id}
          rcdoTree={rcdoTree ?? []}
          existingCommits={commits}
          onSubmit={handleCreateCommit}
          onCancel={handleFormCancel}
          initialValues={commitFormInitialValues}
        />
      )}
      {formMode === "edit" && plan && editingCommit && (
        <CommitForm mode="edit" commit={editingCommit} rcdoTree={rcdoTree ?? []} existingCommits={commits} onSubmit={handleUpdateCommit} onCancel={handleFormCancel} />
      )}
      {scopeChangeMode === "add" && !pendingCreatePayload && plan && (
        <CommitForm mode="create" planId={plan.id} rcdoTree={rcdoTree ?? []} existingCommits={commits} onSubmit={async (payload) => { setPendingCreatePayload(payload); }} onCancel={handleScopeChangeCancel} />
      )}

      {/* Delete confirm */}
      {deleteTarget && !isLocked && (
        <DeleteConfirmDialog title={deleteTarget.title} onConfirm={handleDeleteConfirm} onCancel={() => setDeleteTarget(null)} />
      )}

      {/* Ticket form */}
      {ticketFormVisible && (
        <TicketForm mode="create" initialValues={ticketFormInitialValues} currentUserId={currentUserId} {...(bridge.context.currentTeam ? { currentTeamId: bridge.context.currentTeam.id } : {})} rcdoTree={rcdoTree ?? []} onSubmit={handleTicketFormSubmit} onCancel={() => { setTicketFormVisible(false); setTicketFormInitialValues({}); }} />
      )}

      {/* Lock confirm */}
      {showLockConfirm && plan && (
        <LockConfirmDialog commits={commits} capacityBudgetPoints={plan.capacityBudgetPoints} weekLabel={formatWeekLabel(weekStartDate)} onConfirm={() => void handleLock()} onCancel={() => setShowLockConfirm(false)} isLocking={lockLoading} />
      )}

      {/* Scope change dialogs */}
      {scopeChangeMode === "add" && pendingCreatePayload && (
        <ScopeChangeDialog action="ADD" commit={null} newCommitTitle={pendingCreatePayload.title} onConfirm={(reason) => void handleScopeChangeConfirm(reason)} onCancel={handleScopeChangeCancel} isSubmitting={scopeChangeSaving} />
      )}
      {scopeChangeMode === "edit" && scopeChangeTargetCommit && pendingEditPayload && (
        <ScopeChangeDialog action="EDIT" commit={scopeChangeTargetCommit} proposedChanges={pendingEditPayload as Partial<CommitResponse>} onConfirm={(reason) => void handleScopeChangeConfirm(reason)} onCancel={handleScopeChangeCancel} isSubmitting={scopeChangeSaving} />
      )}
      {scopeChangeMode === "remove" && scopeChangeTargetCommit && (
        <ScopeChangeDialog action="REMOVE" commit={scopeChangeTargetCommit} onConfirm={(reason) => void handleScopeChangeConfirm(reason)} onCancel={handleScopeChangeCancel} isSubmitting={scopeChangeSaving} />
      )}

      {/* Plan History */}
      <Card>
        <CardHeader>
          <CardTitle>Plan History</CardTitle>
          <Button variant="secondary" size="sm" type="button" onClick={() => setShowHistory((s) => !s)} data-testid="toggle-plan-history-btn">
            {showHistory ? "Hide" : "Show history"}
          </Button>
        </CardHeader>
        {showHistory && (
          <CardContent>
            <PlanHistoryView entries={planHistory ?? []} loading={historyLoading} />
          </CardContent>
        )}
      </Card>

      {/* Carry-forward lineage */}
      {lineageCommitId && (
        <Card data-testid="cf-lineage-section">
          <CardHeader>
            <CardTitle>Carry-forward Lineage</CardTitle>
            <Button variant="ghost" size="icon" type="button" onClick={() => setLineageCommitId(null)} aria-label="Close lineage" className="h-7 w-7">
              <X className="h-4 w-4" />
            </Button>
          </CardHeader>
          <CardContent>
            {lineage && <CarryForwardLineageView lineage={lineage} loading={lineageLoading} />}
            {lineageLoading && !lineage && (
              <div data-testid="cf-lineage-loading" role="status" className="text-sm text-muted">Loading lineage…</div>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

/**
 * Reports — operational analytics from derived read-model tables.
 * Route: /weekly/reports
 *
 * Charts are rendered as pure CSS bar/line charts (no charting library dependency).
 * Data comes from 8 pre-computed report endpoints. Several derived metrics are
 * calculated client-side from existing data (velocity, achievement rate, etc.).
 */
import { useState, useEffect, useMemo, useCallback } from "react";
import {
  BarChart3,
  TrendingUp,
  TrendingDown,
  RotateCcw,
  Shield,
  Brain,
  AlertTriangle,
  ChevronLeft,
  ChevronRight,
  Activity,
  Target,
  Zap,
  Clock,
  ShieldAlert,
} from "lucide-react";
import { Card, CardHeader, CardTitle, CardContent } from "../components/ui/Card.js";
import { Badge } from "../components/ui/Badge.js";
import { Button } from "../components/ui/Button.js";
import { useHostBridge } from "../host/HostProvider.js";
import { createApiClient } from "../api/client.js";
import {
  createReportApi,
  type PlannedVsAchievedEntry,
  type CarryForwardReportEntry,
  type ComplianceReportEntry,
  type AiAcceptanceReportEntry,
  type ChessDistributionReportEntry,
  type ScopeChangeReportEntry,
  type ExceptionAgingEntry,
} from "../api/reportApi.js";

// ── Constants ───────────────────────────────────────────────────────────────

const CHESS_ICONS: Record<string, string> = {
  KING: "♔", QUEEN: "♕", ROOK: "♖", BISHOP: "♗", KNIGHT: "♘", PAWN: "♙",
};

const CHESS_ORDER = ["KING", "QUEEN", "ROOK", "BISHOP", "KNIGHT", "PAWN"] as const;

/** Monochrome shades for chess pieces — resolved from CSS vars for dark mode */
const CHESS_SHADES: Record<string, string> = {
  KING: "var(--chess-king)", QUEEN: "var(--chess-queen)", ROOK: "var(--chess-rook)",
  BISHOP: "var(--chess-bishop)", KNIGHT: "var(--chess-knight)", PAWN: "var(--chess-pawn)",
};

// ── Helpers ─────────────────────────────────────────────────────────────────

function weeksAgo(n: number): string {
  const d = new Date();
  const day = d.getDay();
  const diff = day === 0 ? -6 : 1 - day;
  d.setDate(d.getDate() + diff - n * 7);
  return d.toISOString().slice(0, 10);
}

function shortWeek(iso: string): string {
  const d = new Date(`${iso}T00:00:00`);
  return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
}

function pct(n: number, d: number): number {
  return d === 0 ? 0 : Math.round((n / d) * 100);
}

function formatHours(h: number): string {
  if (h < 24) return `${h}h`;
  const days = Math.floor(h / 24);
  const rem = h % 24;
  return rem > 0 ? `${days}d ${rem}h` : `${days}d`;
}

/** Generate list of week-start ISO dates for the range */
function weeksList(rangeWeeks: number): string[] {
  const out: string[] = [];
  for (let i = rangeWeeks - 1; i >= 0; i--) {
    out.push(weeksAgo(i));
  }
  return out;
}

// ── Main Component ──────────────────────────────────────────────────────────

export default function Reports() {
  const bridge = useHostBridge();
  const { authToken } = bridge.context;
  const teamId = bridge.context.currentTeam?.id ?? "";

  const api = useMemo(() => {
    const client = createApiClient({
      baseUrl: "/api",
      getAuthToken: () => bridge.context.authToken,
    });
    return createReportApi(client);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authToken]);

  const [rangeWeeks, setRangeWeeks] = useState(8);
  const weekStart = useMemo(() => weeksAgo(rangeWeeks - 1), [rangeWeeks]);
  const weekEnd = useMemo(() => weeksAgo(0), [rangeWeeks]);
  const weeks = useMemo(() => weeksList(rangeWeeks), [rangeWeeks]);

  // ── Data state ──────────────────────────────────────────────────────────
  const [pva, setPva] = useState<PlannedVsAchievedEntry[]>([]);
  const [cf, setCf] = useState<CarryForwardReportEntry[]>([]);
  const [compliance, setCompliance] = useState<ComplianceReportEntry[]>([]);
  const [aiStats, setAiStats] = useState<AiAcceptanceReportEntry | null>(null);
  const [scopeChanges, setScopeChanges] = useState<ScopeChangeReportEntry[]>([]);
  const [chessDist, setChessDist] = useState<ChessDistributionReportEntry[]>([]);
  const [exceptions, setExceptions] = useState<ExceptionAgingEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Fetch chess distribution for every week in range (API takes single weekStart)
  const fetchAllChess = useCallback(
    async (wks: string[]): Promise<ChessDistributionReportEntry[]> => {
      const results = await Promise.all(
        wks.map((w) =>
          api.getChessDistribution(teamId, w).catch(() => null),
        ),
      );
      return results.filter((r): r is ChessDistributionReportEntry => r !== null);
    },
    [api, teamId],
  );

  useEffect(() => {
    if (!teamId) return;
    setLoading(true);
    setError(null);

    Promise.all([
      api.getPlannedVsAchieved(teamId, weekStart, weekEnd),
      api.getCarryForward(teamId, weekStart, weekEnd),
      api.getCompliance(teamId, weekStart, weekEnd),
      api.getAiAcceptance(),
      api.getScopeChanges(teamId, weekStart, weekEnd),
      fetchAllChess(weeks),
      api.getExceptionAging(teamId),
    ])
      .then(([pvaData, cfData, compData, aiData, scData, chessData, excData]) => {
        setPva(pvaData);
        setCf(cfData);
        setCompliance(compData);
        setAiStats(aiData);
        setScopeChanges(scData);
        setChessDist(chessData);
        setExceptions(excData);
        setLoading(false);
      })
      .catch((err: unknown) => {
        setError(err instanceof Error ? err.message : "Failed to load reports");
        setLoading(false);
      });
  }, [api, teamId, weekStart, weekEnd, weeks, fetchAllChess]);

  return (
    <div className="space-y-6" data-testid="reports-page">
      {/* ── Header ──────────────────────────────────────────────────── */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <BarChart3 className="h-6 w-6 text-primary" />
          <h1 className="text-xl font-bold tracking-tight">Reports & Analytics</h1>
        </div>
        <div className="flex items-center gap-2">
          <Button
            variant="secondary"
            size="sm"
            onClick={() => setRangeWeeks((w) => Math.min(52, w + 4))}
          >
            <ChevronLeft className="h-3 w-3 mr-1" /> More weeks
          </Button>
          <Badge variant="draft">{rangeWeeks} weeks</Badge>
          <Button
            variant="secondary"
            size="sm"
            onClick={() => setRangeWeeks((w) => Math.max(4, w - 4))}
          >
            Fewer <ChevronRight className="h-3 w-3 ml-1" />
          </Button>
        </div>
      </div>

      {loading && <p className="text-sm text-muted animate-pulse">Loading report data…</p>}
      {error && (
        <div className="flex items-center gap-2 text-sm text-danger" role="alert">
          <AlertTriangle className="h-4 w-4" /> {error}
        </div>
      )}

      {!loading && !error && (
        <>
          {/* ── Row 1: Hero velocity ──────────────────────────────── */}
          <VelocityTrendChart data={pva} />

          {/* ── Row 2: Core planning metrics ──────────────────────── */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <PlannedVsAchievedChart data={pva} />
            <AchievementRateChart data={pva} />
          </div>

          {/* ── Row 3: Work composition ───────────────────────────── */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <ChessDistributionChart data={chessDist} />
            <ScopeChangeChart data={scopeChanges} />
          </div>

          {/* ── Row 4: Carry-forward & compliance ─────────────────── */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <CarryForwardChart data={cf} />
            <ComplianceChart data={compliance} />
          </div>

          {/* ── Row 5: Exceptions ─────────────────────────────────── */}
          <ExceptionAgingTable data={exceptions} />

          {/* ── Row 6: AI ─────────────────────────────────────────── */}
          <AiAcceptanceCard data={aiStats} />
        </>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// ── Velocity Trend (hero chart — full width) ────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════

function VelocityTrendChart({ data }: { readonly data: PlannedVsAchievedEntry[] }) {
  const sorted = useMemo(
    () => [...data].sort((a, b) => a.weekStart.localeCompare(b.weekStart)),
    [data],
  );

  const maxPts = Math.max(...sorted.map((d) => d.totalAchievedPoints), 1);

  // Rolling 4-week average
  const rolling = useMemo(() => {
    return sorted.map((_, i) => {
      const window = sorted.slice(Math.max(0, i - 3), i + 1);
      const avg = window.reduce((s, r) => s + r.totalAchievedPoints, 0) / window.length;
      return Math.round(avg);
    });
  }, [sorted]);

  // Trend direction
  const trend = useMemo(() => {
    if (sorted.length < 2) return 0;
    const last = sorted[sorted.length - 1]!.totalAchievedPoints;
    const prev = sorted[sorted.length - 2]!.totalAchievedPoints;
    return last - prev;
  }, [sorted]);

  const chartH = 160;

  return (
    <Card data-testid="velocity-chart">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <Activity className="h-4 w-4 text-foreground" />
          Velocity — Achieved Points per Week
        </CardTitle>
        {trend !== 0 && (
          <div className="flex items-center gap-1 text-xs">
            {trend > 0 ? (
              <TrendingUp className="h-3.5 w-3.5 text-success" />
            ) : (
              <TrendingDown className="h-3.5 w-3.5 text-danger" />
            )}
            <span className={trend > 0 ? "text-success" : "text-danger"}>
              {trend > 0 ? "+" : ""}{trend} pts
            </span>
          </div>
        )}
      </CardHeader>
      <CardContent>
        {sorted.length === 0 ? (
          <p className="text-sm text-muted">No data for this period.</p>
        ) : (
          <div className="relative" style={{ height: chartH + 32 }}>
            {/* Grid lines */}
            <div className="absolute inset-0 flex flex-col justify-between pointer-events-none" style={{ height: chartH }}>
              {[0, 1, 2, 3].map((i) => (
                <div key={i} className="border-b border-border/40 relative">
                  <span className="absolute -top-2 -left-0 text-[9px] text-muted">
                    {Math.round(maxPts * (1 - i / 3))}
                  </span>
                </div>
              ))}
            </div>

            {/* Bars + rolling average dots */}
            <div
              className="absolute inset-0 flex items-end gap-1"
              style={{ height: chartH, paddingLeft: 28 }}
            >
              {sorted.map((row, i) => {
                const barH = (row.totalAchievedPoints / maxPts) * chartH;
                const rollingH = ((rolling[i] ?? 0) / maxPts) * chartH;
                return (
                  <div
                    key={row.weekStart}
                    className="flex-1 flex flex-col items-center justify-end relative"
                    style={{ height: chartH }}
                  >
                    {/* Rolling average marker */}
                    <div
                      className="absolute w-2 h-2 rounded-full bg-foreground border border-surface z-10"
                      style={{ bottom: rollingH - 4 }}
                      title={`4-wk avg: ${rolling[i]}pts`}
                    />
                    {/* Bar */}
                    <div
                      className="w-full bg-foreground/20 hover:bg-foreground/30 transition-all relative group"
                      style={{ height: barH, minHeight: row.totalAchievedPoints > 0 ? 2 : 0 }}
                      title={`${shortWeek(row.weekStart)}: ${row.totalAchievedPoints}pts`}
                    >
                      {/* Tooltip on hover */}
                      <div className="absolute -top-6 left-1/2 -translate-x-1/2 text-[9px] font-bold opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                        {row.totalAchievedPoints}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>

            {/* X-axis labels */}
            <div
              className="absolute bottom-0 flex gap-1"
              style={{ left: 28, right: 0, height: 24 }}
            >
              {sorted.map((row) => (
                <div key={row.weekStart} className="flex-1 text-center text-[9px] text-muted pt-1.5">
                  {shortWeek(row.weekStart)}
                </div>
              ))}
            </div>

            {/* Legend */}
            <div className="absolute top-0 right-0 flex items-center gap-3 text-[10px] text-muted">
              <span className="flex items-center gap-1">
                <span className="inline-block h-2.5 w-4 bg-foreground/20" /> Achieved
              </span>
              <span className="flex items-center gap-1">
                <span className="inline-block h-2 w-2 rounded-full bg-foreground" /> 4-wk avg
              </span>
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// ── Planned vs Achieved ─────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════

function PlannedVsAchievedChart({ data }: { readonly data: PlannedVsAchievedEntry[] }) {
  const sorted = useMemo(
    () => [...data].sort((a, b) => a.weekStart.localeCompare(b.weekStart)),
    [data],
  );
  const maxPts = Math.max(...sorted.map((d) => Math.max(d.totalPlannedPoints, d.totalAchievedPoints)), 1);

  return (
    <Card data-testid="pva-chart">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <TrendingUp className="h-4 w-4 text-primary" />
          Planned vs. Achieved Points
        </CardTitle>
      </CardHeader>
      <CardContent>
        {sorted.length === 0 ? (
          <p className="text-sm text-muted">No data for this period.</p>
        ) : (
          <div className="space-y-2">
            <div className="flex items-center gap-4 text-[10px] text-muted mb-2">
              <span className="flex items-center gap-1"><span className="inline-block h-2 w-4 rounded bg-primary/30" /> Planned</span>
              <span className="flex items-center gap-1"><span className="inline-block h-2 w-4 rounded bg-primary" /> Achieved</span>
            </div>
            {sorted.map((row) => (
              <div key={row.weekStart} className="flex items-center gap-2">
                <span className="w-16 text-[10px] text-muted shrink-0">{shortWeek(row.weekStart)}</span>
                <div className="flex-1 space-y-0.5">
                  <div
                    className="h-3 rounded bg-primary/30 transition-all"
                    style={{ width: `${pct(row.totalPlannedPoints, maxPts)}%` }}
                    title={`Planned: ${row.totalPlannedPoints}pts`}
                  />
                  <div
                    className="h-3 rounded bg-primary transition-all"
                    style={{ width: `${pct(row.totalAchievedPoints, maxPts)}%` }}
                    title={`Achieved: ${row.totalAchievedPoints}pts`}
                  />
                </div>
                <span className="w-20 text-right text-[10px] text-muted shrink-0">
                  {row.totalAchievedPoints}/{row.totalPlannedPoints}pts
                </span>
              </div>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// ── Achievement Rate % ──────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════

function AchievementRateChart({ data }: { readonly data: PlannedVsAchievedEntry[] }) {
  const sorted = useMemo(
    () => [...data].sort((a, b) => a.weekStart.localeCompare(b.weekStart)),
    [data],
  );

  const rates = useMemo(
    () => sorted.map((r) => ({ week: r.weekStart, rate: pct(r.totalAchievedPoints, r.totalPlannedPoints) })),
    [sorted],
  );

  const avgRate = useMemo(() => {
    if (rates.length === 0) return 0;
    return Math.round(rates.reduce((s, r) => s + r.rate, 0) / rates.length);
  }, [rates]);

  const TARGET = 80;
  const chartH = 120;

  return (
    <Card data-testid="achievement-rate-chart">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <Target className="h-4 w-4 text-foreground" />
          Achievement Rate
        </CardTitle>
        <Badge variant={avgRate >= TARGET ? "reconciled" : "locked"}>
          avg {avgRate}%
        </Badge>
      </CardHeader>
      <CardContent>
        {rates.length === 0 ? (
          <p className="text-sm text-muted">No data for this period.</p>
        ) : (
          <div className="relative" style={{ height: chartH + 24 }}>
            {/* Target line */}
            <div
              className="absolute left-0 right-0 border-t border-dashed border-foreground/25 z-10"
              style={{ top: chartH * (1 - TARGET / 100) }}
            >
              <span className="absolute -top-3 right-0 text-[9px] text-muted">{TARGET}% target</span>
            </div>

            {/* Bars */}
            <div className="absolute inset-0 flex items-end gap-1" style={{ height: chartH }}>
              {rates.map((r) => {
                const barH = (r.rate / 100) * chartH;
                const ok = r.rate >= TARGET;
                return (
                  <div
                    key={r.week}
                    className="flex-1 flex flex-col items-center justify-end"
                    style={{ height: chartH }}
                  >
                    <div
                      className={`w-full transition-all ${ok ? "bg-foreground/20" : "bg-foreground/10 border border-dashed border-foreground/20"}`}
                      style={{ height: barH, minHeight: r.rate > 0 ? 2 : 0 }}
                      title={`${shortWeek(r.week)}: ${r.rate}%`}
                    />
                  </div>
                );
              })}
            </div>

            {/* Labels */}
            <div className="absolute bottom-0 flex gap-1" style={{ left: 0, right: 0, height: 24 }}>
              {rates.map((r) => (
                <div key={r.week} className="flex-1 text-center">
                  <span className="text-[9px] font-bold block">{r.rate}%</span>
                  <span className="text-[8px] text-muted block">{shortWeek(r.week)}</span>
                </div>
              ))}
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// ── Chess Distribution ──────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════

function ChessDistributionChart({
  data,
}: {
  readonly data: ChessDistributionReportEntry[];
}) {
  // Aggregate all weeks into one distribution
  const aggregate = useMemo(() => {
    const acc: Record<string, number> = {};
    for (const entry of data) {
      for (const [piece, count] of Object.entries(entry.distribution)) {
        acc[piece] = (acc[piece] ?? 0) + count;
      }
    }
    return acc;
  }, [data]);

  const total = Object.values(aggregate).reduce((s, v) => s + v, 0);

  return (
    <Card data-testid="chess-dist-chart">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <span className="text-base leading-none">♔</span>
          Chess Piece Distribution
        </CardTitle>
        {total > 0 && (
          <span className="text-[10px] text-muted">{total} commits</span>
        )}
      </CardHeader>
      <CardContent>
        {total === 0 ? (
          <p className="text-sm text-muted">No data for this period.</p>
        ) : (
          <div className="space-y-3">
            {/* Stacked bar */}
            <div className="flex h-6 overflow-hidden gap-px">
              {CHESS_ORDER.map((piece) => {
                const count = aggregate[piece] ?? 0;
                if (count === 0) return null;
                const w = (count / total) * 100;
                return (
                  <div
                    key={piece}
                    className="h-full transition-all relative group"
                    style={{
                      width: `${w}%`,
                      backgroundColor: CHESS_SHADES[piece],
                      minWidth: 3,
                    }}
                    title={`${piece}: ${count} (${Math.round(w)}%)`}
                  />
                );
              })}
            </div>

            {/* Breakdown rows */}
            <div className="space-y-1">
              {CHESS_ORDER.map((piece) => {
                const count = aggregate[piece] ?? 0;
                const p = pct(count, total);
                return (
                  <div key={piece} className="flex items-center gap-2 text-xs">
                    <span
                      className="inline-block h-2.5 w-2.5 shrink-0"
                      style={{ backgroundColor: CHESS_SHADES[piece] }}
                    />
                    <span className="w-5 text-center text-sm leading-none">{CHESS_ICONS[piece]}</span>
                    <span className="w-14 font-medium">{piece}</span>
                    <div className="flex-1 bg-surface-raised h-2.5 overflow-hidden">
                      <div
                        className="h-full transition-all"
                        style={{
                          width: `${p}%`,
                          backgroundColor: CHESS_SHADES[piece],
                        }}
                      />
                    </div>
                    <span className="w-8 text-right text-muted">{count}</span>
                    <span className="w-10 text-right font-bold">{p}%</span>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// ── Scope Change Volume ─────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════

function ScopeChangeChart({ data }: { readonly data: ScopeChangeReportEntry[] }) {
  const byWeek = useMemo(() => {
    const map = new Map<string, number>();
    for (const row of data) {
      map.set(row.weekStart, (map.get(row.weekStart) ?? 0) + row.scopeChangeCount);
    }
    return [...map.entries()]
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([week, count]) => ({ week, count }));
  }, [data]);

  const maxCount = Math.max(...byWeek.map((r) => r.count), 1);
  const totalChanges = byWeek.reduce((s, r) => s + r.count, 0);
  const avgChanges = byWeek.length > 0 ? Math.round(totalChanges / byWeek.length) : 0;

  return (
    <Card data-testid="scope-change-chart">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <Zap className="h-4 w-4 text-foreground" />
          Scope Changes
        </CardTitle>
        {byWeek.length > 0 && (
          <span className="text-[10px] text-muted">avg {avgChanges}/wk</span>
        )}
      </CardHeader>
      <CardContent>
        {byWeek.length === 0 ? (
          <p className="text-sm text-muted">No data for this period.</p>
        ) : (
          <div className="space-y-1.5">
            {byWeek.map((row) => {
              const w = pct(row.count, maxCount);
              const isHigh = row.count > avgChanges * 1.5;
              return (
                <div key={row.week} className="flex items-center gap-2">
                  <span className="w-16 text-[10px] text-muted shrink-0">{shortWeek(row.week)}</span>
                  <div className="flex-1 bg-surface-raised h-5 overflow-hidden relative">
                    <div
                      className={`h-full transition-all ${isHigh ? "bg-foreground/30" : "bg-foreground/15"}`}
                      style={{ width: `${Math.max(w, 3)}%` }}
                    />
                    {isHigh && (
                      <span className="absolute right-1.5 top-0.5 text-[8px] font-bold text-foreground/60">
                        HIGH
                      </span>
                    )}
                  </div>
                  <span className="w-8 text-right text-[10px] font-bold shrink-0">{row.count}</span>
                </div>
              );
            })}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// ── Carry-Forward Trends ────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════

function CarryForwardChart({ data }: { readonly data: CarryForwardReportEntry[] }) {
  const byWeek = useMemo(() => {
    const map = new Map<string, { commits: number; carried: number }>();
    for (const row of data) {
      const existing = map.get(row.weekStart) ?? { commits: 0, carried: 0 };
      existing.commits += row.commitCount;
      existing.carried += row.carryForwardCount;
      map.set(row.weekStart, existing);
    }
    return [...map.entries()]
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([week, vals]) => ({ week, ...vals, rate: pct(vals.carried, vals.commits) }));
  }, [data]);

  return (
    <Card data-testid="cf-chart">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <RotateCcw className="h-4 w-4 text-foreground" />
          Carry-Forward Trends
        </CardTitle>
      </CardHeader>
      <CardContent>
        {byWeek.length === 0 ? (
          <p className="text-sm text-muted">No data for this period.</p>
        ) : (
          <div className="space-y-2">
            {byWeek.map((row) => (
              <div key={row.week} className="flex items-center gap-2">
                <span className="w-16 text-[10px] text-muted shrink-0">{shortWeek(row.week)}</span>
                <div className="flex-1 bg-surface-raised overflow-hidden h-5 relative">
                  <div
                    className="h-full bg-foreground/25 transition-all flex items-center px-1.5"
                    style={{ width: `${Math.max(row.rate, 5)}%` }}
                  >
                    <span className="text-[9px] font-bold text-foreground">{row.rate}%</span>
                  </div>
                </div>
                <span className="w-20 text-right text-[10px] text-muted shrink-0">
                  {row.carried}/{row.commits}
                </span>
              </div>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// ── Compliance Chart ────────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════

function ComplianceChart({ data }: { readonly data: ComplianceReportEntry[] }) {
  const byWeek = useMemo(() => {
    const map = new Map<string, { total: number; lockedOnTime: number; reconciledOnTime: number; autoLocked: number }>();
    for (const row of data) {
      const existing = map.get(row.weekStart) ?? { total: 0, lockedOnTime: 0, reconciledOnTime: 0, autoLocked: 0 };
      existing.total++;
      if (row.lockOnTime) existing.lockedOnTime++;
      if (row.reconcileOnTime) existing.reconciledOnTime++;
      if (row.autoLocked) existing.autoLocked++;
      map.set(row.weekStart, existing);
    }
    return [...map.entries()]
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([week, v]) => ({
        week,
        lockRate: pct(v.lockedOnTime, v.total),
        reconcileRate: pct(v.reconciledOnTime, v.total),
        autoLockRate: pct(v.autoLocked, v.total),
        total: v.total,
      }));
  }, [data]);

  return (
    <Card data-testid="compliance-chart">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <Shield className="h-4 w-4 text-success" />
          Lock & Reconcile Compliance
        </CardTitle>
      </CardHeader>
      <CardContent>
        {byWeek.length === 0 ? (
          <p className="text-sm text-muted">No data for this period.</p>
        ) : (
          <div className="space-y-2">
            <div className="flex items-center gap-4 text-[10px] text-muted mb-2">
              <span className="flex items-center gap-1">
                <span className="inline-block h-2 w-4 bg-foreground/70" /> Lock on time
              </span>
              <span className="flex items-center gap-1">
                <span className="inline-block h-2 w-4 bg-foreground/30" /> Reconcile on time
              </span>
              <span className="flex items-center gap-1">
                <span className="inline-block h-2 w-4 bg-foreground/10 border border-dashed border-foreground/30" /> Auto-locked
              </span>
            </div>
            {byWeek.map((row) => (
              <div key={row.week} className="flex items-center gap-2">
                <span className="w-16 text-[10px] text-muted shrink-0">{shortWeek(row.week)}</span>
                <div className="flex-1 space-y-0.5">
                  <div className="flex gap-px h-3">
                    <div
                      className="h-full bg-foreground/70 transition-all"
                      style={{ width: `${row.lockRate}%` }}
                      title={`Lock: ${row.lockRate}%`}
                    />
                    {row.autoLockRate > 0 && (
                      <div
                        className="h-full bg-foreground/10 border border-dashed border-foreground/30 transition-all"
                        style={{ width: `${row.autoLockRate}%` }}
                        title={`Auto-locked: ${row.autoLockRate}%`}
                      />
                    )}
                  </div>
                  <div
                    className="h-3 bg-foreground/30 transition-all"
                    style={{ width: `${row.reconcileRate}%` }}
                    title={`Reconcile: ${row.reconcileRate}%`}
                  />
                </div>
                <span className="w-24 text-right text-[10px] text-muted shrink-0">
                  {row.lockRate}% / {row.reconcileRate}%
                </span>
              </div>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// ── Exception Aging Table ───────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════

const SEVERITY_STYLES: Record<string, string> = {
  CRITICAL: "border-foreground bg-foreground text-primary-foreground",
  HIGH: "border-foreground/50 bg-foreground/10 text-foreground",
  MEDIUM: "border-border bg-muted-bg text-muted",
  LOW: "border-border bg-surface text-muted",
};

const EXCEPTION_LABELS: Record<string, string> = {
  MISSED_LOCK: "Missed lock",
  AUTO_LOCKED: "Auto-locked",
  MISSED_RECONCILE: "Missed reconcile",
  OVER_BUDGET: "Over budget",
  REPEATED_CARRY_FORWARD: "Repeat carry-fwd",
  POST_LOCK_SCOPE_INCREASE: "Scope increase",
  KING_CHANGED_POST_LOCK: "King changed",
  HIGH_SCOPE_VOLATILITY: "High volatility",
};

function ExceptionAgingTable({ data }: { readonly data: ExceptionAgingEntry[] }) {
  const sorted = useMemo(
    () => [...data].sort((a, b) => b.ageInHours - a.ageInHours),
    [data],
  );

  const criticalCount = sorted.filter((e) => e.severity === "CRITICAL" || e.severity === "HIGH").length;

  return (
    <Card data-testid="exception-aging-table">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <ShieldAlert className="h-4 w-4 text-foreground" />
          Exception Aging — Unresolved
        </CardTitle>
        <div className="flex items-center gap-2">
          {criticalCount > 0 && (
            <Badge variant="locked">{criticalCount} urgent</Badge>
          )}
          <Badge variant="draft">{sorted.length} open</Badge>
        </div>
      </CardHeader>
      <CardContent>
        {sorted.length === 0 ? (
          <div className="flex items-center gap-2 py-4 text-sm text-muted">
            <Shield className="h-4 w-4" />
            No unresolved exceptions. All clear.
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full border-collapse text-xs" aria-label="Unresolved exceptions">
              <thead>
                <tr className="border-b border-border">
                  <th className="px-2 py-1.5 text-left text-[10px] font-semibold uppercase text-muted">Severity</th>
                  <th className="px-2 py-1.5 text-left text-[10px] font-semibold uppercase text-muted">Type</th>
                  <th className="px-2 py-1.5 text-left text-[10px] font-semibold uppercase text-muted">Week</th>
                  <th className="px-2 py-1.5 text-right text-[10px] font-semibold uppercase text-muted">Age</th>
                  <th className="px-2 py-1.5 text-right text-[10px] font-semibold uppercase text-muted">Status</th>
                </tr>
              </thead>
              <tbody>
                {sorted.map((exc) => (
                  <tr key={exc.exceptionId} className="border-b border-border/50 hover:bg-muted-bg/50">
                    <td className="px-2 py-1.5">
                      <span
                        className={`inline-flex items-center px-1.5 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${
                          SEVERITY_STYLES[exc.severity] ?? SEVERITY_STYLES.LOW
                        }`}
                      >
                        {exc.severity}
                      </span>
                    </td>
                    <td className="px-2 py-1.5 font-medium">
                      {EXCEPTION_LABELS[exc.exceptionType] ?? exc.exceptionType}
                    </td>
                    <td className="px-2 py-1.5 text-muted">{shortWeek(exc.weekStartDate)}</td>
                    <td className="px-2 py-1.5 text-right font-bold">
                      <span className="flex items-center justify-end gap-1">
                        <Clock className="h-3 w-3 text-muted" />
                        {formatHours(exc.ageInHours)}
                      </span>
                    </td>
                    <td className="px-2 py-1.5 text-right">
                      {exc.ageInHours >= 72 ? (
                        <span className="text-[9px] font-bold uppercase tracking-wider text-danger">STALE</span>
                      ) : exc.ageInHours >= 24 ? (
                        <span className="text-[9px] font-bold uppercase tracking-wider text-warning">AGING</span>
                      ) : (
                        <span className="text-[9px] font-bold uppercase tracking-wider text-muted">NEW</span>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// ── AI Acceptance ───────────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════

function AiAcceptanceCard({ data }: { readonly data: AiAcceptanceReportEntry | null }) {
  if (!data) return null;
  const rate = Math.round(data.acceptanceRate * 100);
  const feedbackRate = data.totalSuggestions > 0
    ? Math.round((data.totalFeedbackGiven / data.totalSuggestions) * 100)
    : 0;
  const meetsTarget = rate >= 25;

  return (
    <Card data-testid="ai-acceptance-card">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <Brain className="h-4 w-4 text-primary" />
          AI Suggestion Acceptance
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
          <StatBox label="Total Suggestions" value={data.totalSuggestions.toLocaleString()} />
          <StatBox label="Feedback Given" value={data.totalFeedbackGiven.toLocaleString()} />
          <StatBox label="Accepted" value={data.acceptedCount.toLocaleString()} accent="text-success" />
          <StatBox label="Dismissed" value={data.dismissedCount.toLocaleString()} />
          <StatBox label="Feedback Rate" value={`${feedbackRate}%`} accent={feedbackRate >= 50 ? "text-success" : "text-muted"} />
        </div>
        <div className="mt-4 space-y-2">
          {/* Acceptance rate */}
          <div className="flex items-center gap-3">
            <span className="text-[10px] text-muted w-20 shrink-0 uppercase tracking-wide">Acceptance</span>
            <div className="flex-1 bg-surface-raised h-4 overflow-hidden">
              <div
                className="h-full bg-foreground/20 transition-all"
                style={{ width: `${rate}%` }}
              />
            </div>
            <span className="text-sm font-bold w-10 text-right">{rate}%</span>
            <Badge variant={meetsTarget ? "reconciled" : "locked"}>
              {meetsTarget ? "Above 25%" : "Below 25%"}
            </Badge>
          </div>
          {/* Feedback engagement rate */}
          <div className="flex items-center gap-3">
            <span className="text-[10px] text-muted w-20 shrink-0 uppercase tracking-wide">Engagement</span>
            <div className="flex-1 bg-surface-raised h-4 overflow-hidden">
              <div
                className="h-full bg-foreground/10 transition-all"
                style={{ width: `${feedbackRate}%` }}
              />
            </div>
            <span className="text-sm font-bold w-10 text-right">{feedbackRate}%</span>
            <span className="text-[10px] text-muted">of suggestions reviewed</span>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// ── Shared components ───────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════

function StatBox({
  label,
  value,
  accent,
}: {
  readonly label: string;
  readonly value: string;
  readonly accent?: string;
}) {
  return (
    <div className="rounded-default border border-border bg-surface-raised p-3 text-center">
      <p className="text-[10px] font-medium text-muted uppercase tracking-wide">{label}</p>
      <p className={`text-lg font-bold mt-0.5 ${accent ?? ""}`}>{value}</p>
    </div>
  );
}

import { type HTMLAttributes } from "react";
import { cn } from "../../lib/utils.js";

function Skeleton({ className, ...props }: HTMLAttributes<HTMLDivElement>) {
  return (
    <div
      className={cn(
