/**
 * AI commit lint panel — replaces the placeholder in PreLockValidationPanel.
 * Calls POST /api/ai/commit-lint and displays hard + soft lint messages
 * with feedback buttons on each.
 *
 * When `autoRun` is true the lint API is called automatically on mount and
 * whenever `planId` changes — no button click required.  The manual refresh
 * button is still shown inside the results view so users can re-run after
 * editing commits.
 */
import { useState, useCallback, useEffect, useRef } from "react";
import { Bot, RefreshCw } from "lucide-react";
import { Button } from "../ui/Button.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import { useAiApi, useAiStatus } from "../../api/aiHooks.js";
import type { CommitLintResponse } from "../../api/aiApi.js";

interface AiLintPanelProps {
  planId: string;
  userId: string;
  /** When true, lint fires automatically on mount and on planId change (no button click required). */
  autoRun?: boolean;
  /**
   * Monotonically increasing counter. Every time this value changes the lint
   * re-fires (debounced). Callers should increment it after any commit
   * create / edit / delete / reorder operation so lint results stay current.
   */
  refreshKey?: number;
}

export function AiLintPanel({ planId, userId, autoRun = false, refreshKey = 0 }: AiLintPanelProps) {
  const aiApi = useAiApi();
  const { data: status } = useAiStatus();
  const [lintResult, setLintResult] = useState<CommitLintResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const isAvailable = status?.available ?? false;

  const runLint = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const result = await aiApi.commitLint({ userId, planId });
      setLintResult(result);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Lint failed");
    } finally {
      setLoading(false);
    }
  }, [aiApi, planId, userId]);

  // Auto-run: fire lint on mount (and whenever planId changes) when AI is available.
  // Guard on isAvailable so we don't kick off a doomed request when AI is down.
  useEffect(() => {
    if (!autoRun || !isAvailable) return;
    void runLint();
  }, [autoRun, planId, isAvailable, runLint]);

  // Re-run with debounce when refreshKey changes (after commit CRUD operations).
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const prevRefreshKeyRef = useRef(refreshKey);
  useEffect(() => {
    // Skip the initial mount — the effect above already covers that.
    if (refreshKey === prevRefreshKeyRef.current) return;
    prevRefreshKeyRef.current = refreshKey;
    if (!autoRun || !isAvailable) return;

    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      void runLint();
    }, 800);

    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
    };
  }, [refreshKey, autoRun, isAvailable, runLint]);

  // AI not available — show disabled state
  if (status && !status.available) {
    return (
      <div className="flex items-center gap-2 rounded-default border border-dashed border-border bg-background/60 px-3 py-2.5 text-xs text-muted italic" data-testid="ai-lint-unavailable">
        <Bot className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
        AI commit quality hints unavailable ({status.providerName})
      </div>
    );
  }

  // Not yet run:
  //   - autoRun=false  → show the manual trigger button
  //   - autoRun=true   → lint is about to fire (or waiting for status); render nothing
  //                       so there is no flash of a button that immediately disappears
  if (!lintResult && !loading) {
    if (autoRun) {
      return null;
    }
    return (
      <div className="flex items-center gap-2" data-testid="ai-lint-ready">
        <Button variant="ghost" size="sm" onClick={() => void runLint()} className="h-7 text-xs border border-dashed border-border" data-testid="ai-lint-run-btn">
          <Bot className="h-3.5 w-3.5" />
          Run AI Quality Check
        </Button>
      </div>
    );
  }

  // Loading
  if (loading) {
    return (
      <div className="flex items-center gap-2 text-xs text-muted animate-pulse" data-testid="ai-lint-loading">
        <Bot className="h-3.5 w-3.5 shrink-0" />
        Analyzing commit quality…
      </div>
    );
  }

  // Error
  if (error) {
    return (
      <div className="flex items-center gap-2 text-xs text-danger" data-testid="ai-lint-error">
        <Bot className="h-3.5 w-3.5 shrink-0" />
        {error}
        <Button variant="ghost" size="sm" onClick={() => void runLint()} className="h-6 text-xs">
          <RefreshCw className="h-3 w-3" />Retry
        </Button>
      </div>
    );
  }

  // Results
  if (!lintResult?.aiAvailable) {
    return (
      <div className="text-xs text-muted italic" data-testid="ai-lint-unavailable">
        <Bot className="h-3.5 w-3.5 inline mr-1" />AI lint unavailable
      </div>
    );
  }

  const hasHard = lintResult.hardValidation.length > 0;
  const hasSoft = lintResult.softGuidance.length > 0;

  return (
    <div className="flex flex-col gap-2" data-testid="ai-lint-results">
      {/* Header with refresh */}
      <div className="flex items-center justify-between">
        <span className="flex items-center gap-1.5 text-xs font-semibold text-muted">
          <Bot className="h-3.5 w-3.5" />AI Quality Check
        </span>
        <div className="flex items-center gap-1.5">
          {lintResult.suggestionId && <AiFeedbackButtons suggestionId={lintResult.suggestionId} />}
          <Button variant="ghost" size="sm" onClick={() => void runLint()} className="h-6 text-xs" data-testid="ai-lint-refresh">
            <RefreshCw className="h-3 w-3" />
          </Button>
        </div>
      </div>

      {/* Hard validations */}
      {hasHard && (
        <div className="rounded-sm border border-neutral-300 bg-neutral-100 px-3 py-2" data-testid="ai-lint-hard">
          <p className="m-0 mb-1 text-xs font-bold text-foreground underline">Hard Issues</p>
          <ul className="m-0 pl-4 flex flex-col gap-0.5">
            {lintResult.hardValidation.map((msg, i) => (
              <li key={i} className="text-xs text-foreground">{msg.message}</li>
            ))}
          </ul>
        </div>
      )}

      {/* Soft guidance */}
      {hasSoft && (
        <div className="rounded-sm border border-neutral-200 bg-neutral-50 px-3 py-2" data-testid="ai-lint-soft">
          <p className="m-0 mb-1 text-xs font-semibold text-muted">Suggestions</p>
          <ul className="m-0 pl-4 flex flex-col gap-0.5">
            {lintResult.softGuidance.map((msg, i) => (
              <li key={i} className="text-xs text-muted">{msg.message}</li>
            ))}
          </ul>
        </div>
      )}

      {/* All clear */}
      {!hasHard && !hasSoft && (
        <div className="text-xs text-foreground flex items-center gap-1" data-testid="ai-lint-clear">
          ✓ No quality issues detected
        </div>
      )}
    </div>
  );
}

/**
 * ProactiveRiskBanner — displays critical AI-detected risk signals as
 * prominent, persistent banners on the IC's own My Week page.
 *
 * The parent (MyWeek) is responsible for only rendering this component
 * when the plan is LOCKED. Risk signals are filtered to the three critical
 * types that warrant immediate IC attention:
 *   OVERCOMMIT, BLOCKED_CRITICAL, REPEATED_CARRY_FORWARD
 *
 * Non-critical types (UNDERCOMMIT, SCOPE_VOLATILITY) are excluded — they
 * are surfaced on the Team Week risk tab instead.
 */
import { AlertTriangle, ShieldAlert, TrendingDown, RotateCcw } from "lucide-react";
import { cn } from "../../lib/utils.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import { useRiskSignals } from "../../api/aiHooks.js";
import type { RiskSignal } from "../../api/aiApi.js";

// ── Critical signal type filter ───────────────────────────────────────────────

/** Signal types shown as proactive IC banners on My Week. */
const CRITICAL_SIGNAL_TYPES = new Set([
  "OVERCOMMIT",
  "BLOCKED_CRITICAL",
  "REPEATED_CARRY_FORWARD",
]);

// ── Per-type display config ───────────────────────────────────────────────────

interface SignalConfig {
  Icon: typeof AlertTriangle;
  /** Tailwind border + background classes for the banner. */
  cls: string;
  /** Short actionable hint shown below the rationale. */
  actionHint: string;
}

const SIGNAL_CONFIG: Record<string, SignalConfig> = {
  OVERCOMMIT: {
    Icon: TrendingDown,
    cls: "border-neutral-400 bg-neutral-100",
    actionHint: "Consider reducing scope before the week runs out.",
  },
  BLOCKED_CRITICAL: {
    Icon: ShieldAlert,
    cls: "border-neutral-400 bg-neutral-100",
    actionHint: "Resolve the blocked ticket or escalate to your manager.",
  },
  REPEATED_CARRY_FORWARD: {
    Icon: RotateCcw,
    cls: "border-neutral-300 bg-neutral-50",
    actionHint:
      "Review whether this work needs to be broken down or deprioritised.",
  },
};

// ── Individual banner ─────────────────────────────────────────────────────────

function RiskBannerItem({ signal }: { signal: RiskSignal }) {
  const config = SIGNAL_CONFIG[signal.signalType];
  const Icon = config?.Icon ?? AlertTriangle;
  const cls = config?.cls ?? "border-border bg-background";
  const actionHint = config?.actionHint;

  return (
    <div
      className={cn(
        "rounded-default border px-4 py-3 flex items-start gap-3",
        cls,
      )}
      role="alert"
      data-testid={`risk-banner-${signal.id}`}
    >
      <Icon
        className="h-4 w-4 mt-0.5 shrink-0 text-foreground"
        aria-hidden="true"
      />
      <div className="flex-1 min-w-0">
        <div className="flex items-start justify-between gap-2">
          <div className="flex-1 min-w-0">
            <p
              className="m-0 text-sm font-semibold text-foreground"
              data-testid={`risk-banner-type-${signal.id}`}
            >
              {signal.signalType.replace(/_/g, " ")}
            </p>
            <p
              className="m-0 text-sm text-foreground leading-relaxed mt-0.5"
              data-testid={`risk-banner-rationale-${signal.id}`}
            >
              {signal.rationale}
            </p>
            {actionHint && (
              <p
                className="m-0 text-xs text-muted italic mt-1"
                data-testid={`risk-banner-action-${signal.id}`}
              >
                → {actionHint}
              </p>
            )}
          </div>
          {/* signal.id is the AiSuggestion PK — suitable as feedback target */}
          <AiFeedbackButtons suggestionId={signal.id} />
        </div>
      </div>
    </div>
  );
}

// ── Main component ────────────────────────────────────────────────────────────

interface ProactiveRiskBannerProps {
  /** Plan UUID. The parent must only render this for LOCKED plans. */
  planId: string;
}

/**
 * Renders zero or more alert banners for critical AI risk signals.
 * Returns `null` when AI is unavailable, loading, errored, or when no
 * critical signals exist — so callers need no conditional guard.
 */
export function ProactiveRiskBanner({ planId }: ProactiveRiskBannerProps) {
  const { data, loading, error } = useRiskSignals(planId);

  // Keep the UI clean: no loading skeleton for proactive banners.
  if (loading) return null;

  // Silently degrade when AI is unavailable or the fetch failed.
  if (error || !data?.aiAvailable) return null;

  const criticalSignals = data.signals.filter((s) =>
    CRITICAL_SIGNAL_TYPES.has(s.signalType),
  );

  if (criticalSignals.length === 0) return null;

  return (
    <div
      className="flex flex-col gap-2"
      data-testid="proactive-risk-banners"
      aria-label="Active risk signals"
    >
      {criticalSignals.map((signal) => (
        <RiskBannerItem key={signal.id} signal={signal} />
      ))}
    </div>
  );
}

/**
 * SoftWarningsPanel — UI-only soft warnings, never lock blockers.
 */
import { AlertTriangle } from "lucide-react";
import type { CommitResponse } from "../../api/planTypes.js";

const SOFT_MAX_COMMITS = 8;
const PAWN_POINT_WARNING_THRESHOLD = 0.4;

export interface SoftWarningsPanelProps {
  readonly commits: CommitResponse[];
}

export function SoftWarningsPanel({ commits }: SoftWarningsPanelProps) {
  const activeCommits = commits.filter((c) => c.outcome == null);
  const totalPoints = commits.reduce((sum, c) => sum + (c.estimatePoints ?? 0), 0);
  const pawnPoints = commits.filter((c) => c.chessPiece === "PAWN").reduce((sum, c) => sum + (c.estimatePoints ?? 0), 0);

  const tooManyCommits = activeCommits.length > SOFT_MAX_COMMITS;
  const tooManyPawns = totalPoints > 0 && pawnPoints / totalPoints > PAWN_POINT_WARNING_THRESHOLD;

  if (!tooManyCommits && !tooManyPawns) return null;

  return (
    <div data-testid="soft-warnings-panel" aria-live="polite" className="flex flex-col gap-2">
      {tooManyCommits && (
        <div
          role="status"
          data-testid="warning-too-many-commits"
          className="flex items-start gap-2 px-3 py-2.5 rounded-default border border-neutral-300 bg-neutral-100 text-sm text-foreground"
        >
          <AlertTriangle className="h-4 w-4 shrink-0 mt-0.5 text-neutral-500" aria-hidden="true" />
          <span>
            <strong>Too many commits:</strong> you have {activeCommits.length} active commits. Consider focusing on
            fewer items for better weekly throughput (recommended: ≤{SOFT_MAX_COMMITS}).
          </span>
        </div>
      )}

      {tooManyPawns && (
        <div
          role="status"
          data-testid="warning-pawn-heavy"
          className="flex items-start gap-2 px-3 py-2.5 rounded-default border border-neutral-300 bg-neutral-100 text-sm text-foreground"
        >
          <AlertTriangle className="h-4 w-4 shrink-0 mt-0.5 text-neutral-500" aria-hidden="true" />
          <span>
            <strong>Pawn-heavy plan:</strong> {Math.round((pawnPoints / totalPoints) * 100)}% of your points are Pawn
            commits. Consider elevating strategic work.
          </span>
        </div>
      )}
    </div>
  );
}

